svg.script:
(function () {
  var front = document.getElementById('frontAssembly');
  var frontShadow = document.getElementById('frontShadow');
  var sideFace = document.getElementById('sideFace');
  var rimLine = document.getElementById('rimLine');
  var knob = document.getElementById('knob');
  var btnLeft = document.getElementById('btnLeft');
  var btnRight = document.getElementById('btnRight');
  var trackHit = document.getElementById('trackHit');

  var frontClipPoints = [
    [0, 1024], [0, 555], [45, 510], [95, 468], [140, 404], [190, 352],
    [250, 321], [290, 318], [332, 112], [372, 317], [425, 329], [490, 386],
    [560, 447], [645, 500], [725, 548], [805, 596], [840, 630], [840, 1024]
  ];

  var trackMin = 557;
  var trackMax = 979;
  var pivotX = 332;
  var pivotY = 214;
  var maxAngle = 72;
  var angle = 0;
  var dragging = false;

  function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
  }

  function angleToX(value) {
    return trackMin + ((value + maxAngle) / (maxAngle * 2)) * (trackMax - trackMin);
  }

  function xToAngle(x) {
    var clamped = clamp(x, trackMin, trackMax);
    return ((clamped - trackMin) / (trackMax - trackMin)) * (maxAngle * 2) - maxAngle;
  }

  function translatePoints(points, dx, dy) {
    return points.map(function (point) {
      return [point[0] + dx, point[1] + dy];
    });
  }

  function toPath(points) {
    if (!points.length) return '';
    var commands = ['M ' + points[0][0].toFixed(2) + ' ' + points[0][1].toFixed(2)];
    for (var index = 1; index < points.length; index += 1) {
      commands.push('L ' + points[index][0].toFixed(2) + ' ' + points[index][1].toFixed(2));
    }
    commands.push('Z');
    return commands.join(' ');
  }

  function buildSideFace(basePoints, depthX, depthY, facingRight) {
    var edgeIndexes = facingRight ? [8, 9, 10, 11, 12, 13, 14, 15, 16] : [1, 2, 3, 4, 5, 6, 7, 8];
    var facePoints = [];
    edgeIndexes.forEach(function (index) {
      facePoints.push(basePoints[index]);
    });
    for (var reverseIndex = edgeIndexes.length - 1; reverseIndex >= 0; reverseIndex -= 1) {
      var point = basePoints[edgeIndexes[reverseIndex]];
      facePoints.push([point[0] + depthX, point[1] + depthY]);
    }
    return facePoints;
  }

  function buildRim(basePoints, depthX, depthY, facingRight) {
    var edgeIndexes = facingRight ? [8, 9, 10, 11, 12, 13, 14, 15, 16] : [1, 2, 3, 4, 5, 6, 7, 8];
    var rimPoints = edgeIndexes.map(function (index) {
      var point = basePoints[index];
      return [point[0] + depthX, point[1] + depthY];
    });
    return toPath(rimPoints).replace(/ Z$/, '');
  }

  function render() {
    var rad = angle * Math.PI / 180;
    var scaleX = Math.max(0.18, Math.cos(rad));
    var pushX = Math.sin(rad) * 54;
    var riseY = -Math.abs(Math.sin(rad)) * 8;
    var tinyRotate = angle * 0.07;
    var depthX = Math.sin(rad) * 118;
    var depthY = Math.abs(Math.sin(rad)) * 24;
    var shadowX = Math.sin(rad) * 72;
    var shadowY = 28 + Math.abs(Math.sin(rad)) * 14;
    var faceOpacity = Math.min(0.88, Math.abs(Math.sin(rad)) * 0.95);
    var shadowOpacity = Math.min(0.32, Math.abs(Math.sin(rad)) * 0.60);
    var rimOpacity = Math.min(0.82, Math.abs(Math.sin(rad)) * 1.05);
    var facingRight = angle >= 0;

    front.setAttribute(
      'transform',
      'rotate(' + tinyRotate + ' ' + pivotX + ' ' + pivotY + ') ' +
      'translate(' + pushX.toFixed(2) + ' ' + riseY.toFixed(2) + ') ' +
      'translate(' + pivotX + ' ' + pivotY + ') ' +
      'matrix(' + scaleX.toFixed(5) + ' 0 0 1 0 0) ' +
      'translate(' + (-pivotX) + ' ' + (-pivotY) + ')'
    );

    sideFace.setAttribute('d', toPath(buildSideFace(frontClipPoints, depthX, depthY, facingRight)));
    sideFace.setAttribute('opacity', faceOpacity.toFixed(3));

    rimLine.setAttribute('d', buildRim(frontClipPoints, depthX, depthY, facingRight));
    rimLine.setAttribute('opacity', rimOpacity.toFixed(3));

    frontShadow.setAttribute('d', toPath(translatePoints(frontClipPoints, shadowX, shadowY)));
    frontShadow.setAttribute('opacity', shadowOpacity.toFixed(3));

    knob.setAttribute('cx', angleToX(angle));
  }

  function setAngle(nextAngle) {
    angle = clamp(nextAngle, -maxAngle, maxAngle);
    render();
  }

  function pointerX(evt) {
    if (evt.touches && evt.touches.length) return evt.touches[0].clientX;
    if (evt.changedTouches && evt.changedTouches.length) return evt.changedTouches[0].clientX;
    return evt.clientX;
  }

  function localSvgPoint(clientX) {
    var svg = document.documentElement;
    var pt = svg.createSVGPoint();
    pt.x = clientX;
    pt.y = 0;
    var ctm = svg.getScreenCTM();
    if (!ctm) return clientX;
    return pt.matrixTransform(ctm.inverse()).x;
  }

  function startDrag(evt) {
    dragging = true;
    evt.preventDefault();
  }

  function moveDrag(evt) {
    if (!dragging) return;
    var x = localSvgPoint(pointerX(evt));
    setAngle(xToAngle(x));
    evt.preventDefault();
  }

  function endDrag() {
    dragging = false;
  }

  knob.addEventListener('mousedown', startDrag);
  knob.addEventListener('touchstart', startDrag, { passive: false });
  trackHit.addEventListener('mousedown', function (evt) {
    var x = localSvgPoint(pointerX(evt));
    setAngle(xToAngle(x));
    dragging = true;
    evt.preventDefault();
  });
  trackHit.addEventListener('touchstart', function (evt) {
    var x = localSvgPoint(pointerX(evt));
    setAngle(xToAngle(x));
    dragging = true;
    evt.preventDefault();
  }, { passive: false });

  document.addEventListener('mousemove', moveDrag);
  document.addEventListener('touchmove', moveDrag, { passive: false });
  document.addEventListener('mouseup', endDrag);
  document.addEventListener('touchend', endDrag);
  document.addEventListener('touchcancel', endDrag);

  btnLeft.addEventListener('click', function () { setAngle(angle - 12); });
  btnRight.addEventListener('click', function () { setAngle(angle + 12); });

  render();
})();
